@dataclass
class DocumentChunk:
    doc_id: str
    source: str
    chunk_id: int
    text: str
    metadata: Dict[str, Any]


class DocumentLoader:
    def __init__(self, data_dir: str):
        self.data_dir = data_dir

    def load(self) -> List[Tuple[str, str]]:
        files = []
        patterns = ["**/*.txt", "**/*.md", "**/*.json"]
        for pattern in patterns:
            files.extend(glob.glob(os.path.join(self.data_dir, pattern), recursive=True))
        docs = []
        for path in sorted(set(files)):
            try:
                docs.append((path, self._read_file(path)))
            except Exception:
                continue
        return docs

    def _read_file(self, path: str) -> str:
        ext = os.path.splitext(path)[1].lower()
        if ext in [".txt", ".md"]:
            with open(path, "r", encoding="utf-8", errors="ignore") as f:
                return f.read()
        if ext == ".json":
            with open(path, "r", encoding="utf-8", errors="ignore") as f:
                obj = json.load(f)
            return json.dumps(obj, ensure_ascii=False, indent=2)
        with open(path, "r", encoding="utf-8", errors="ignore") as f:
            return f.read()


class TextSplitter:
    def __init__(self, chunk_size: int = 1000, chunk_overlap: int = 150):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap

    def split(self, text: str) -> List[str]:
        text = text.replace("\r\n", "\n").strip()
        if not text:
            return []
        chunks = []
        start = 0
        n = len(text)
        while start < n:
            end = min(start + self.chunk_size, n)
            chunk = text[start:end].strip()
            if chunk:
                chunks.append(chunk)
            if end >= n:
                break
            start = max(0, end - self.chunk_overlap)
        return chunks


class VectorStore:
    def __init__(self, embedding_model_name: str = "all-MiniLM-L6-v2", index_path: str = "rag_index.faiss", meta_path: str = "rag_meta.pkl"):
        self.embedding_model_name = embedding_model_name
        self.index_path = index_path
        self.meta_path = meta_path
        self.model = SentenceTransformer(embedding_model_name)
        self.index = None
        self.chunks: List[DocumentChunk] = []
        self.dimension = self.model.get_sentence_embedding_dimension()

    def build(self, documents: List[Tuple[str, str]], chunk_size: int = 1000, chunk_overlap: int = 150):
        splitter = TextSplitter(chunk_size=chunk_size, chunk_overlap=chunk_overlap)
        all_chunks: List[DocumentChunk] = []
        texts = []
        for source, content in documents:
            doc_id = hashlib.sha1(source.encode("utf-8")).hexdigest()[:16]
            parts = splitter.split(content)
            for i, part in enumerate(parts):
                chunk = DocumentChunk(
                    doc_id=doc_id,
                    source=source,
                    chunk_id=i,
                    text=part,
                    metadata={"source": source, "doc_id": doc_id, "chunk_id": i},
                )
                all_chunks.append(chunk)
                texts.append(part)
        if not texts:
            self.index = faiss.IndexFlatIP(self.dimension)
            self.chunks = []
            return
        embeddings = self.model.encode(texts, convert_to_numpy=True, show_progress_bar=True, normalize_embeddings=True).astype("float32")
        index = faiss.IndexFlatIP(self.dimension)
        index.add(embeddings)
        self.index = index
        self.chunks = all_chunks

    def save(self):
        if self.index is None:
            raise ValueError("Index is not built")
        faiss.write_index(self.index, self.index_path)
        with open(self.meta_path, "wb") as f:
            pickle.dump(self.chunks, f)

    def load(self):
        self.index = faiss.read_index(self.index_path)
        with open(self.meta_path, "rb") as f:
            self.chunks = pickle.load(f)

    def search(self, query: str, top_k: int = 5) -> List[DocumentChunk]:
        if self.index is None:
            raise ValueError("Index is not loaded or built")
        q = self.model.encode([query], convert_to_numpy=True, normalize_embeddings=True).astype("float32")
        scores, idxs = self.index.search(q, top_k)
        results = []
        for idx in idxs[0]:
            if idx == -1:
                continue
            if 0 <= idx < len(self.chunks):
                results.append(self.chunks[idx])
        return results


class RAGChatbot:
    def __init__(self, vector_store: VectorStore, openai_api_key: Optional[str] = None, model: str = "gpt-4o-mini"):
        self.vector_store = vector_store
        self.model = model
        self.client = OpenAI(api_key=openai_api_key or os.getenv("OPENAI_API_KEY")) if OpenAI else None

    def build_prompt(self, query: str, retrieved: List[DocumentChunk]) -> List[Dict[str, str]]:
        context_blocks = []
        for i, chunk in enumerate(retrieved, 1):
            context_blocks.append(
                f"[Document {i}]\nSource: {chunk.source}\nChunk: {chunk.chunk_id}\nContent:\n{chunk.text}"
            )
        context = "\n\n".join(context_blocks) if context_blocks else "No relevant context found."
        system = (
            "You are an internal company knowledge base assistant. "
            "Answer using only the provided context. "
            "If the answer is not in the context, say you don't know. "
            "Cite the source document names when possible."
        )
        user = f"Question:\n{query}\n\nRetrieved Context:\n{context}"
        return [{"role": "system", "content": system}, {"role": "user", "content": user}]

    def answer(self, query: str, top_k: int = 5) -> Dict[str, Any]:
        retrieved = self.vector_store.search(query, top_k=top_k)
        messages = self.build_prompt(query, retrieved)
        if self.client is None:
            return {
                "query": query,
                "answer": "OpenAI client not available. Set OPENAI_API_KEY and install openai.",
                "retrieved": [chunk.__dict__ for chunk in retrieved],
                "messages": messages,
            }
        response = self.client.chat.completions.create(
            model=self.model,
            messages=messages,
            temperature=0.2,
        )
        answer = response.choices[0].message.content
        return {
            "query": query,
            "answer": answer,
            "retrieved": [chunk.__dict__ for chunk in retrieved],
            "messages": messages,
        }


def build_index(data_dir: str, index_path: str = "rag_index.faiss", meta_path: str = "rag_meta.pkl"):
    loader = DocumentLoader(data_dir)
    docs = loader.load()
    store = VectorStore(index_path=index_path, meta_path=meta_path)
    store.build(docs)
    store.save()
    return store


def load_index(index_path: str = "rag_index.faiss", meta_path: str = "rag_meta.pkl") -> VectorStore:
    store = VectorStore(index_path=index_path, meta_path=meta_path)
    store.load()
    return store


def main():
    import argparse

    parser = argparse.ArgumentParser(description="Internal RAG chatbot")
    parser.add_argument("--data_dir", type=str, default="documents")
    parser.add_argument("--build", action="store_true")
    parser.add_argument("--query", type=str, default=None)
    parser.add_argument("--top_k", type=int, default=5)
    parser.add_argument("--index_path", type=str, default="rag_index.faiss")
    parser.add_argument("--meta_path", type=str, default="rag_meta.pkl")
    parser.add_argument("--model", type=str, default="gpt-4o-mini")
    args = parser.parse_args()

    if args.build:
        build_index(args.data_dir, args.index_path, args.meta_path)

    store = load_index(args.index_path, args.meta_path)
    bot = RAGChatbot(store, model=args.model)

    if args.query:
        result = bot.answer(args.query, top_k=args.top_k)
        print(result["answer"])
        return

    while True:
        try:
            query = input("Query> ").strip()
        except (EOFError, KeyboardInterrupt):
            break
        if not query or query.lower() in {"exit", "quit"}:
            break
        result = bot.answer(query, top_k=args.top_k)
        print("\nAnswer:\n", result["answer"])
        print("\nRetrieved Sources:")
        for item in result["retrieved"]:
            print(f"- {item['source']} (chunk {item['chunk_id']})")
        print()


if __name__ == "__main__":
    main()